    _step_2 = proof.use(nfv, subst={"ph": "wmo(ph, x)", "x": "y"})  # ⊢ wnf(wmo(ph, x), y)
    _step_3 = proof.use(nfe1, subst={"ph": "wa(ph, ps)", "x": "x"})  # ⊢ wnf(wex(wa(ph, ps), x), x)
    _step_4 = proof.use(nfmov, _step_3, subst={"y": "y"})  # ⊢ wnf(wmo(wex(wa(ph, ps), x), y), x)
