@mm_2euexv.proof
def prove_mm_2euexv(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s001 import biimtrid, sylbi, sylib
    from metamath_setmm_provider.shards.s002 import impcom
