    _step_4 = proof.use(
        imbi1i,
        _step_3,
        subst={
            "ch": "wa(wceq(cv(x), cv(z)), wceq(cv(y), cv(w)))",
        },
    )  # ⊢ wb(wi(wa(ph, wsb(wsb(ph, y, w), x, z)), wa(wceq(cv(x), cv(z)), wceq(cv(y), cv(w)))), wi(…
    _step_5 = proof.use(
        mm_2albii,
        _step_4,
        subst={
            "x": "z",
            "y": "w",
        },
    )  # ⊢ wb(wal(wal(wi(wa(ph, wsb(wsb(ph, y, w), x, z)), wa(wceq(cv(x), cv(z)), wceq(cv(y), cv(w)…
    _step_6 = proof.use(
        mm_2albii,
        _step_5,
        subst={
            "x": "x",
            "y": "y",
        },
    )  # ⊢ wb(wal(wal(wal(wal(wi(wa(ph, wsb(wsb(ph, y, w), x, z)), wa(wceq(cv(x), cv(z)), wceq(cv(y…
    _step_7 = proof.use(
        bitri,
        _step_1,
        _step_6,
    )  # ⊢ wb(wex(wex(wal(wal(wi(ph, wa(wceq(cv(x), cv(z)), wceq(cv(y), cv(w)))), y), x), w), z), w…
    return proof.qed(_step_7)


